SELECT

FROM email_verification
WHERE email = #{email}
  AND user_type = #{userType}
  AND verification_type = #{verificationType}
  AND verification_code = #{verificationCode}
  AND is_verified = 0
  AND expire_time > #{currentTime}
LIMIT 1

mapper.update:
UPDATE email_verification
SET is_verified = 1,
    verified_time = #{verifiedTime},
    updated_time = #{verifiedTime}
WHERE email = #{email}
  AND user_type = #{userType}
  AND verification_type = #{verificationType}
  AND verification_code = #{verificationCode}
  AND is_verified = 0

